/*===================================================================================================================================*/
/*  U1      u1_d_NvmcMod_GetErrDetectCode(const U4 * const u4_ap_DATA, const U1 u1_a_SIZE, U4 * u4_ap_code)                          */
/* --------------------------------------------------------------------------------------------------------------------------------- */
/*  Arguments:      --> u4_ap_DATA  : Data                                                                                           */
/*                  --> u1_a_SIZE   : Data Size                                                                                      */
/*                  --> *u4_ap_code : Code                                                                                           */
/*  Return:         U1 u1_t_ret : TRUE / FALSE                                                                                       */
/*===================================================================================================================================*/
U1      u1_d_NvmcMod_GetErrDetectCode(const U4 * const u4_ap_DATA, const U1 u1_a_SIZE, U4 * u4_ap_code)
{
    U1  u1_t_ret;

    u1_t_ret = (U1)FALSE;
    if(u4_ap_DATA != vdp_PTR_NA){
        *u4_ap_code = u4_g_Crc32((U4)NVMC_MOD_CFG_CRC_INIT_VALUE,
                                 (const U1 *)u4_ap_DATA,
                                 ((U4)u1_a_SIZE * (U4)NVMC_MOD_CFG_CRC_SIZE_OFFSET),
                                 (U1)TRUE);
        u1_t_ret = (U1)TRUE;
    }

    return (u1_t_ret);
}

